function _demoId() {
  return 'demo_' + Date.now().toString(36) + Math.random().toString(36).substr(2, 9);
}

function _buildDemoGames() {
  const S = _DEMO_RAW.s;
  const games = [];
  const allBowls = [];

  for (let gi = 0; gi < _DEMO_RAW.g.length; gi++) {
    const raw = _DEMO_RAW.g[gi];
    const [tournament, date, format, opposition, players, oppPlayers, totalEnds, endScores, rawBowls] = raw;

    const gameId = _demoId();
    const isPairs = format.includes('Pairs');
    const bowlsPerPlayer = isPairs ? 4 : 4;
    const playersPerTeam = isPairs ? players.length : 1;

    const game = {
      id: gameId,
      gameId: gameId,
      tournamentName: tournament,
      format: isPairs ? 'pairs4' : 'singles',
      gameType: 'game',
      matchStructure: 'traditional',
      totalEnds: totalEnds,
      endCount: totalEnds,
      currentEnd: totalEnds,
      completed: true,
      date: date + 'T10:00:00.000Z',
      yourPlayers: players,
      players: players,
      opponentPlayers: oppPlayers,
      awayPlayers: [],
      bowlsPerPlayer: bowlsPerPlayer,
      playersPerTeam: playersPerTeam,
      numberOfSets: null,
      endsPerSet: null,
      tieBreakEnds: null,
      currentSet: 1,
      setScores: [],
      endNotes: {},
      gameNotes: '',
      jackPosition: { x: 250, y: 250 },
      bowls: [],
      currentPlayerIndex: 0,
      currentTeam: 'yours',
      currentHand: 'forehand',
      matLength: 'short',
      jackLength: 'medium',
      gameNumber: gi + 1,
      [DEMO_DATA_MARKER]: true
    };

    games.push(game);

    // Expand compressed bowls
    for (let bi = 0; bi < rawBowls.length; bi++) {
      const rb = rawBowls[bi];
      const playerName = S[rb[0]];
      const endNum = rb[1];
      const bowlNum = rb[2];
      const team = rb[3] === 0 ? 'yours' : 'opponent';
      const hand = rb[4] >= 0 ? S[rb[4]] : 'Forehand';
      const shotType = rb[5] >= 0 ? S[rb[5]] : 'Draw shot';
      const resultCat = rb[6] >= 0 ? S[rb[6]] : '';
      const score = rb[7] >= 0 ? rb[7] : null;
      const jackLen = rb[8] >= 0 ? S[rb[8]] : 'Medium';
      const matLen = rb[9] >= 0 ? S[rb[9]] : 'Medium';

      // Determine position
      let position = 'Player';
      if (isPairs) {
        const pIdx = players.indexOf(playerName);
        const oIdx = oppPlayers.indexOf(playerName);
        if (pIdx === 0 || oIdx === 0) position = 'Lead';
        else if (pIdx > 0 || oIdx > 0) position = 'Skip';
      }

      allBowls.push({
        id: _demoId(),
        gameId: gameId,
        endNumber: endNum,
        end: endNum,
        bowlNumber: bowlNum,
        player: playerName,
        playerName: playerName,
        playerId: playerName,
        team: team,
        hand: hand,
        position: position,
        x: 200 + Math.floor(Math.random() * 100),
        y: 200 + Math.floor(Math.random() * 100),
        scoreValue: score,
        score: score,
        resultCategory: resultCat,
        direction: resultCat,
        distanceInFeet: score !== null ? (score >= 4 ? 0.3 : score >= 3 ? 0.8 : score >= 2 ? 1.5 : score >= 1 ? 2.5 : 4.0) : 2.0,
        distance: score !== null ? (score >= 4 ? 0.3 : score >= 3 ? 0.8 : score >= 2 ? 1.5 : score >= 1 ? 2.5 : 4.0) : 2.0,
        matLength: matLen,
        jackLength: jackLen,
        shotType: shotType,
        quality: score !== null ? (score >= 3 ? 'good' : (score >= 2 ? 'average' : 'poor')) : 'average',
        isDead: false,
        notes: '',
        timestamp: new Date(date + 'T10:00:00.000Z').toISOString(),
        [DEMO_DATA_MARKER]: true
      });
    }
  }

  return { games, bowls: allBowls };
}

